code = """import json
import pandas as pd
import os

# Read the stored data using the exact variable names provided
# The keys are: var_functions.query_db:42 and var_functions.query_db:43
children_books_raw = var_functions.query_db_42
reviews_raw = var_functions.query_db_43

# Load children's books data
if isinstance(children_books_raw, str) and os.path.exists(children_books_raw):
    with open(children_books_raw, 'r') as f:
        child_books = json.load(f)
else:
    child_books = children_books_raw

# Load reviews data  
if isinstance(reviews_raw, str) and os.path.exists(reviews_raw):
    with open(reviews_raw, 'r') as f:
        reviews = json.load(f)
else:
    reviews = reviews_raw

print('Loaded data successfully:')
print(f'- Children books: {len(child_books)}')
print(f'- Reviews: {len(reviews)}')

# Prepare dataframes
books_df = pd.DataFrame(child_books)
reviews_df = pd.DataFrame(reviews)

# Create clean IDs for matching
books_df['clean_id'] = books_df['book_id'].str.replace('bookid_', '')
reviews_df['clean_id'] = reviews_df['purchase_id'].str.replace('purchaseid_', '')

# Convert rating to float
reviews_df['rating'] = pd.to_numeric(reviews_df['rating'])

# Merge datasets
merged = pd.merge(reviews_df, books_df, left_on='clean_id', right_on='clean_id', how='inner')

print(f'Matched {len(merged)} review-book pairs')

# Calculate statistics
book_stats = merged.groupby(['book_id', 'title']).agg({'rating': ['mean', 'count']})
book_stats.columns = ['avg_rating', 'review_count']
book_stats = book_stats.reset_index()
book_stats['avg_rating'] = book_stats['avg_rating'].round(2)

# Filter high-rated books
high_rated = book_stats[book_stats['avg_rating'] >= 4.5]

# Sort results
result = high_rated.sort_values(['avg_rating', 'review_count'], ascending=[False, False])

# Output JSON
print('__RESULT__:')
print(result.to_json(orient='records'))"""

